def _parse_event_deltas():
    text = (REPO_ROOT / "scripts" / "score-update.sh").read_text(encoding="utf-8")
    m = re.search(r'EVENT_DELTAS\s*=\s*\{(.*?)\n\}', text, flags=re.DOTALL)
    assert m, "EVENT_DELTAS dict not found in scripts/score-update.sh"
    body = m.group(1)
    out = {}
    for line in body.splitlines():
        line = line.strip().rstrip(",")
        em = re.match(r'"([a-z_0-9]+)"\s*:\s*\{(.*)\}\s*$', line)
        if not em:
            continue
        event = em.group(1)
        agents = {}
        for am in re.finditer(r'"(dev|ba|qa)"\s*:\s*(-?\d+)', em.group(2)):
            agents[am.group(1)] = int(am.group(2))
        out[event] = agents
    return out


